528			return nil
529		}
530		var paths []string
531		seen := map[string]bool{}
532		for _, line := range strings.Split(string(out), "\n") {
533			line = strings.TrimRight(line, "\r")
534			if strings.TrimSpace(line) == "" || len(line) < 4 {
535				continue
536			}
537			path := strings.TrimSpace(line[3:])
538			if idx := strings.Index(path, " -> "); idx >= 0 {
539				path = strings.TrimSpace(path[idx+4:])
540			}
541			if path == "" || seen[path] {
542				continue
