551	// applied when landEvidence / VerifyCleanWorktree stage the evidence
552	// directory. Only excludes the multi-thousand-line embedded session log
553	// (the single file that actually explodes past provider context
554	// limits). prompt.md, usage.json, manifest.json, and result.json remain
555	// tracked — they are small and serve the audit-trail contract. The
556	// gitignore written by `ddx init` already treats .ddx/executions/*/
557	// embedded as ignored; this pathspec is defence-in-depth for force-add
558	// paths.
559	//
560	// Regression anchor: ddx-39e27896 — session logs landed as tracked
561	// evidence caused retry prompts to balloon past 2M+ tokens and crash
562	// every provider with n_keep > n_ctx.
563	func EvidenceLandExcludePathspecs() []string {
564		return []string{
565			":(exclude,glob).ddx/executions/*/embedded/**",
566		}
567	}
