 643	func normalizePreDispatchDirtyPaths(paths []string) []string {
 644		seen := make(map[string]bool, len(paths))
 645		normalized := make([]string, 0, len(paths))
 646		for _, path := range paths {
 647			path = filepath.ToSlash(strings.TrimSpace(path))
 648			if path == "" || seen[path] {
 649				continue
 650			}
 651			seen[path] = true
 652			normalized = append(normalized, path)
 653		}
 654		sort.Strings(normalized)
 655		return normalized
 656	}
 657	
 658	func intersectPreDispatchDirtyPaths(current, want []string) []string {
 659		if len(current) == 0 || len(want) == 0 {
 660			return nil
 661		}
 662		wantSet := make(map[string]bool, len(want))
 663		for _, path := range want {
 664			wantSet[path] = true
 665		}
 666		var overlap []string
 667		for _, path := range current {
 668			if wantSet[path] {
 669				overlap = append(overlap, path)
 670			}
 671		}
 672		sort.Strings(overlap)
 673		return overlap
 674	}
